"use strict";(self.webpackChunktil_wiki=self.webpackChunktil_wiki||[]).push([["7186"],{9516(n){n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2026/04/30/first-post","metadata":{"permalink":"/ailog/blog/2026/04/30/first-post","editUrl":"https://github.com/journeyxcode/ailog/tree/main/blog/2026-04-30-first-post.md","source":"@site/blog/2026-04-30-first-post.md","title":"Android \uAC1C\uBC1C\uC790, AI\uB97C \uC2DC\uC791\uD558\uB2E4","description":"Android \uAC1C\uBC1C\uC790\uB85C \uC77C\uD574\uC628 \uC81C\uAC00, AI \uC5D4\uC9C0\uB2C8\uC5B4\uB85C\uC758 \uC804\uD658\uC744 \uC900\uBE44\uD558\uBA70 \uADF8 \uC5EC\uC815\uC744 \uAE30\uB85D\uD558\uAE30 \uC704\uD574 \uC774 \uBE14\uB85C\uADF8\uB97C \uC2DC\uC791\uD569\uB2C8\uB2E4.","date":"2026-04-30T00:00:00.000Z","tags":[{"inline":true,"label":"AI","permalink":"/ailog/blog/tags/ai"},{"inline":true,"label":"TIL","permalink":"/ailog/blog/tags/til"},{"inline":true,"label":"Start","permalink":"/ailog/blog/tags/start"}],"readingTime":0.75,"hasTruncateMarker":true,"authors":[{"name":"journeyxcode","url":"https://github.com/journeyxcode","socials":{},"key":null,"page":null}],"frontMatter":{"title":"Android \uAC1C\uBC1C\uC790, AI\uB97C \uC2DC\uC791\uD558\uB2E4","date":"2026-04-30T00:00:00.000Z","authors":{"name":"journeyxcode","url":"https://github.com/journeyxcode"},"tags":["AI","TIL","Start"]},"unlisted":false},"content":"Android \uAC1C\uBC1C\uC790\uB85C \uC77C\uD574\uC628 \uC81C\uAC00, AI \uC5D4\uC9C0\uB2C8\uC5B4\uB85C\uC758 \uC804\uD658\uC744 \uC900\uBE44\uD558\uBA70 \uADF8 \uC5EC\uC815\uC744 \uAE30\uB85D\uD558\uAE30 \uC704\uD574 \uC774 \uBE14\uB85C\uADF8\uB97C \uC2DC\uC791\uD569\uB2C8\uB2E4.\\n\\n{/* truncate */}\\n\\n## \uC65C \uC2DC\uC791\uD588\uB098\uC694?\\n\\nAndroid \uAC1C\uBC1C\uC790\uB85C \uC571 \uAC1C\uBC1C \uBC0F \uB2E4\uC218 \uD504\uB85C\uC81D\uD2B8\uB97C \uC9C4\uD589\uD558\uBA70 \uC77C\uD574\uC654\uC2B5\uB2C8\uB2E4.\\n\\n\uC791\uB144 \uAC00\uC744 \uC2DC\uC791\uD55C \uBD80\uD2B8\uCEA0\uD504\uC5D0\uC11C \uB9CE\uC740 \uC6B0\uC5EC\uACE1\uC808\uC774 \uC788\uC5C8\uC2B5\uB2C8\uB2E4.\\n\uC774\uC81C \uBD80\uD2B8\uCEA0\uD504\uAC00 \uACE7 \uB05D\uB098\uAC11\uB2C8\uB2E4. \uC544\uC9C1 \uB9CE\uC774 \uBD80\uC871\uD55C \uB370 \uC798\uD560 \uC218 \uC788\uC744\uC9C0 \uAC71\uC815\uC774 \uB429\uB2C8\uB2E4.\\n\\n\uC800\uB294 AI \uC5D4\uC9C0\uB2C8\uC5B4\uB85C \uC9C1\uBB34 \uC804\uD658\uC744 \uBAA9\uD45C\uB85C \uC900\uBE44\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4.\\n\uADF8\uB3D9\uC548 \uACF5\uBD80\uD588\uB358 \uB0B4\uC6A9\uB4E4\uACFC \uCD5C\uC2E0 \uC18C\uC2DD\uB4E4 \uADF8\uB9AC\uACE0 \uC800\uC640 \uAC19\uC740 AI \uBD84\uC57C\uC5D0 \uB3C4\uC804\uD558\uC2DC\uB294 \uBD84\uB4E4\uC5D0\uAC8C\uB3C4 \uB3C4\uC6C0\uC774 \uB418\uB294 \uB0B4\uC6A9\uC744 \uACF5\uC720\uD558\uACE0 \uC2F6\uC2B5\uB2C8\uB2E4.\\n\\n\uC544\uC9C1\uB3C4 \uBC30\uC6CC\uC57C \uD560 \uAC83\uB4E4\uC774 \uB9CE\uC9C0\uB9CC \uBAB8\uC18C \uBD80\uB52A\uD788\uBA70 \uB9CC\uB4E4\uC5B4 \uAC00\uACA0\uC2B5\uB2C8\uB2E4.\\n\\n\\n## \uC774 \uBE14\uB85C\uADF8\uB294 \uC5B4\uB5A4 \uACF5\uAC04\uC778\uAC00\uC694?\\n\\nAI LOG\uB294 \uB2E8\uC21C\uD55C \uD559\uC2B5 \uC77C\uC9C0\uAC00 \uC544\uB2D9\uB2C8\uB2E4.\\n\\n- \uACF5\uBD80\uD55C \uB0B4\uC6A9\uC744 \uB098\uB9CC\uC758 \uC5B8\uC5B4\uB85C \uC815\uB9AC\uD55C \uAE30\uC220 \uBB38\uC11C\\n- \uC9C1\uC811 \uAD6C\uD604\uD558\uACE0 \uC2E4\uD328\uD558\uACE0 \uAC1C\uC120\uD55C \uD504\uB85C\uC81D\uD2B8 \uACBD\uD5D8\\n- AI \uC5D4\uC9C0\uB2C8\uC5B4\uB85C \uC77C\uD560 \uC900\uBE44\uB97C \uC704\uD55C \uC9C0\uB098\uC628 \uD754\uC801\uB4E4\\n- AI, \uBAA8\uBC14\uC77C \uBD84\uC57C\uC758 \uCD5C\uC2E0 \uC18C\uC2DD\uACFC \uB17C\uBB38 \uB9AC\uBDF0\\n\\n\uC77D\uB294 \uC0AC\uB78C\uC5D0\uAC8C\uB3C4 \uB3C4\uC6C0\uC774 \uB418\uB294 \uAE00\uC744 \uC4F0\uB294 \uAC83\uC744 \uBAA9\uD45C\uB85C \uD569\uB2C8\uB2E4.\\n\\n## \uC55E\uC73C\uB85C\uC758 \uACC4\uD68D\\n\\nAI \uAE30\uBCF8\uAE30\uBD80\uD130 \uC2DC\uC791\uD574 \uD504\uB85C\uC81D\uD2B8 \uACBD\uD5D8, \uCD5C\uC2E0 \uC18C\uC2DD\uAE4C\uC9C0 \uAFB8\uC900\uD788 \uCC44\uC6CC\uB098\uAC08 \uC608\uC815\uC785\uB2C8\uB2E4.\\n\\n\uC644\uBCBD\uD558\uC9C0 \uC54A\uC544\uB3C4 \uAD1C\uCC2E\uC2B5\uB2C8\uB2E4. \uAFB8\uC900\uD568\uC774 \uAC00\uC7A5 \uAC15\uD55C \uBB34\uAE30\uB77C\uACE0 \uBBFF\uC73C\uB2C8\uAE4C\uC694.\\n\\n> \u{1F431} Happy Coding!"}]}}')}}]);